    except (MigrationError, sqlite3.Error) as e:
        try:
            cursor.execute("RELEASE migration_op")
        except (NameError, sqlite3.Error):
            pass
        try:
            conn.rollback()
        except NameError:
            pass
        print(f"Error: {e}", file=sys.stderr)
        return 1


